import torch
import torch.nn as nn

class Expert(nn.Module):
    """专家网络：通常是前馈神经网络"""
    def __init__(self, dim, hidden_dim):
        super().__init__()
        self.ffn = nn.Sequential(
            nn.Linear(dim, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, dim)
        )

    def forward(self, x):
        return self.ffn(x)
